class Solution:
    def areAlmostEqual(self, s1, s2):
        if len(s1) != len(s2):
            return False
        diff = [i for i in range(len(s1)) if s1[i] != s2[i]]
        if len(diff) == 0:
            return True
        if len(diff) == 2:
            i, j = diff
            return s1[i] == s2[j] and s1[j] == s2[i]
        return False

