class Solution:
    def areAlmostEqual(self, s1, s2):
        pairs = [(a, b) for a, b in zip(s1, s2) if a != b]
        if not pairs:
            return True
        if len(pairs) != 2:
            return False
        (a1, b1), (a2, b2) = pairs
        return a1 == b2 and b1 == a2

