var areAlmostEqual = function(s1, s2) {
    const pairs = [];
    for (let i = 0; i < s1.length; i++) {
        if (s1[i] !== s2[i]) pairs.push([s1[i], s2[i]]);
    }
    if (pairs.length === 0) return true;
    if (pairs.length !== 2) return false;
    return pairs[0][0] === pairs[1][1] && pairs[0][1] === pairs[1][0];
};
